select * from customer limit 20

-- Q1what is the total reveue generated by male vs female customers?

select gender,Sum(purchase_amount) as revenue
from customer
group by gender


--Q2which customer used a discount but still spent more than the average purcahse amount?

select customer_id, purchase_amount
from customer
where discount_applied = 'Yes' and purchase_amount >= (select Avg(purchase_amount) 
from customer)



--Q2 which are the top 5  products with highest average review rating?

select item_purchased , Round(avg(review_rating::numeric),2) as "average product rating"
from customer
group by item_purchased 
order by avg(review_rating) desc
limit 5

--Q3 compare the average purchase amount between standard and express shipping?


select shipping_type, round(avg (purchase_amount),2) 
from customer
where shipping_type in ('Standard','Express')
group by shipping_type




--Q5 do subscribed customers spend more? compare average spend and total Revenue between subscribers and non_subscribers?

 select subscription_status,
 count(customer_id) as total_customers,
 Round(avg(purchase_amount),2) as avg_spend,
 Round(sum(purchase_amount),2) as total_revenue
 from customer
 group by subscription_status
 order by total_revenue,avg_spend desc;

 --Q6 which 5 products have the highest percentage of purchases with discount applied?

 select item_purchased,
 Round(100 * sum(case when discount_applied = 'Yes' Then 1 Else 0 end)/ Count(*),2) as discount_rate
 from customer
 group by item_purchased
 order by discount_rate desc
 limit 5;



 --Q7 segment customers into new, returning and loyal based on their 
 --total number of previous purchase, and show the count of each segment?

with customer_type as (
select customer_id, previous_purchases,
case
    when previous_purchases = 1 Then 'New'
	when previous_purchases between 2 and 10 then 'Returning'
	else 'loyal '
	end as customer_segment
from customer
)


select customer_segment,count(*) as "No of customers"
from customer_type
group by customer_segment


--Q8 what are the top 3 most purchased products within each category?

with item_counts as (
select category,
item_purchased,
count(customer_id) as total_orders,
row_number() over(partition by category order by count(customer_id) desc) as item_rank
from customer
group by category, item_purchased
)
 
select item_rank,category, item_purchased,total_orders
from item_counts
where item_rank <= 3;


--Q9 are customers who are repeat buyers(more than 5 previous purchases) also
--likely to subscribe?

select subscription_status,
count(customer_id) as repeat_customers
from customer
where previous_purchases > 5
group by subscription_status


--Q10 what is the revenue contribution of each age group?

select age_group,
sum(purchase_amount) as total_revenue
from customer
group by age_group
order by total_revenue desc;



 





